+++ uthread_file.c      Thu Apr 16 23:51:22 1998
@@ -42,10 +42,12 @@
        int             fd, flags;
        int             status;
How-To-Repeat: 
Save this to a file, ie blah.c.

#include <pthread.h>
#include <stdio.h>

main()
{
        FILE*   fBlah = NULL;

        fprintf(fBlah, "Blah\n");
}


Then do this:

  gcc -lc_r -o blah blah.c
  ./blah

hangs. Have to 'kill -9' to stop.


But this:

  gcc -o blah blah.c
  ./blah

core dumps as expected.
